import { useState } from "react";
import { useNavigate } from "react-router-dom";
import "./login.scss";
import axios from "axios";
import { login as loginApi } from "../api/auth";

export default function Login() {
  const [loginView, setLoginView] = useState(true);
  const [zoomDirection, setZoomDirection] = useState("out");

  const [signInForm, setSignInForm] = useState({
    email: "",
    password: "",
  });

  const [signUpForm, setSignUpForm] = useState({
    name: "",
    email: "",
    password: "",
    role: "hacker",
  });

  const [error, setError] = useState("");
  const navigate = useNavigate();

  /* =========================
     🔐 SIGN IN
  ========================= */
  const handleSignIn = async (e) => {
    e.preventDefault();
    setError("");

    try {
      const res = await loginApi(
        signInForm.email,
        signInForm.password
      );

      const { token, user } = res.data;

      localStorage.setItem("token", token);
      localStorage.setItem("role", user.role);
      localStorage.setItem("username", user.name || user.email);

      if (user.role === "hacker") {
        navigate("/hacker", { replace: true });
      } else {
        navigate("/company", { replace: true });
      }

    } catch (err) {
      setError("Invalid credentials");
    }
  };

  /* =========================
     🆕 SIGN UP
  ========================= */
  const handleSignUp = async (e) => {
    e.preventDefault();
    setError("");

    try {
      const res = await axios.post(
        "http://localhost:5000/api/auth/register",
        signUpForm
      );

      const { token, user } = res.data;

      localStorage.setItem("token", token);
      localStorage.setItem("role", user.role);
      localStorage.setItem("username", user.name || user.email);

      if (user.role === "company") {
        navigate("/company", { replace: true });
      } else {
        navigate("/hacker", { replace: true });
      }

    } catch (err) {
      setError(err.response?.data?.msg || "Registration failed");
    }
  };

  /* =========================
     🔁 Toggle
  ========================= */
  const handleToggle = () => {
    setLoginView(!loginView);
    setZoomDirection(loginView ? "in" : "out");
  };

  return (
    <div
      className={`login zoom-${zoomDirection} ${
        signUpForm.role === "company" ? "company-theme" : ""
      }`}
    >
      {/* LEFT PANEL */}
      <div className="login__welcome-back">
        <div className="login__welcome-back__main-container">
          <div className="login__welcome-back__main-container__text-container">
            <h2>
              {signUpForm.role === "company"
                ? "Company Portal"
                : "Hacker Console"}
            </h2>
            <p>
              {loginView
                ? "Already have an account?"
                : "Create a new account"}
            </p>
          </div>

          <button
            className="toggle-btn"
            onClick={handleToggle}
          >
            {loginView ? "Login" : "Create Account"}
          </button>
        </div>
      </div>

      {/* CREATE ACCOUNT */}
      {!loginView && (
        <div className="form-container">
          <h2>Create Account</h2>

          {error && <p className="error">{error}</p>}

          <form onSubmit={handleSignUp}>
            <input
              placeholder="Full Name"
              value={signUpForm.name}
              onChange={(e) =>
                setSignUpForm({ ...signUpForm, name: e.target.value })
              }
            />

            <input
              placeholder="Email"
              value={signUpForm.email}
              onChange={(e) =>
                setSignUpForm({ ...signUpForm, email: e.target.value })
              }
            />

            <input
              placeholder="Password"
              type="password"
              value={signUpForm.password}
              onChange={(e) =>
                setSignUpForm({ ...signUpForm, password: e.target.value })
              }
            />

            <select
              value={signUpForm.role}
              onChange={(e) =>
                setSignUpForm({ ...signUpForm, role: e.target.value })
              }
            >
              <option value="hacker">Hacker</option>
              <option value="company">Company</option>
            </select>

            <button type="submit" className="main-btn">
              Sign Up
            </button>
          </form>
        </div>
      )}

      {/* LOGIN FORM */}
      {loginView && (
        <div className="form-container">
          <h2>Login</h2>

          {error && <p className="error">{error}</p>}

          <form onSubmit={handleSignIn}>
            <input
              placeholder="Email"
              value={signInForm.email}
              onChange={(e) =>
                setSignInForm({ ...signInForm, email: e.target.value })
              }
            />

            <input
              placeholder="Password"
              type="password"
              value={signInForm.password}
              onChange={(e) =>
                setSignInForm({ ...signInForm, password: e.target.value })
              }
            />

            <button type="submit" className="main-btn">
              Login
            </button>
          </form>
        </div>
      )}
    </div>
  );
}
